// src/Tools.jsx
import React from "react";
import { useNavigate } from "react-router-dom";

const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function Tools({ employee }) {
  const navigate = useNavigate();

  if (!employee)
    return (
      <div style={outer}>
        <div style={center}>
          <p>Please login again.</p>
        </div>
      </div>
    );

  return (
    <div style={outer}>
      <div style={card}>
        {/* BACK BUTTON + TITLE */}
        <div style={headerRow}>
          <button onClick={() => navigate("/home")} style={backBtn}>
            ⬅ Back
          </button>
          <h2 style={title}>Tools</h2>
        </div>

        {/* EMPLOYEE INFO */}
        <p style={empInfo}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* CARDS WRAPPER */}
        <div style={cardsWrapper}>

          {/* CARD 1: MONTHLY GRAPH */}
          <div
            style={toolCard}
            onClick={() => navigate("/tools/graph")}
          >
            <h3 style={cardTitle}>Monthly Expense Graph</h3>
            <p style={cardText}>View your monthly travel & ticket expense summary with charts.</p>
          </div>

          {/* CARD 2: UPLOAD BILLS */}
          <div
            style={toolCard}
            onClick={() => navigate("/tools/upload-bills")}
          >
            <h3 style={cardTitle}>Upload Bills</h3>
            <p style={cardText}>Upload your bills & receipts for tracking and reimbursement.</p>
          </div>

        </div>
      </div>
    </div>
  );
}

// ---------- STYLES ----------
const outer = {
  minHeight: "100vh",
  background: lightGreen,
  padding: 20,
  fontFamily: "Segoe UI",
};

const card = {
  maxWidth: 950,
  margin: "0 auto",
  background: "#fff",
  padding: 20,
  borderRadius: 16,
  boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
};

const headerRow = { display: "flex", alignItems: "center", gap: 10 };
const backBtn = {
  background: "none",
  border: "none",
  color: green,
  fontSize: 16,
  cursor: "pointer",
};
const title = { color: green, margin: 0 };
const empInfo = { fontSize: 13, color: "#555", marginTop: 6 };

const cardsWrapper = {
  display: "flex",
  flexDirection: "column",
  gap: 16,
  marginTop: 20,
};

const toolCard = {
  padding: 18,
  borderRadius: 12,
  border: "1px solid #e1f5e8",
  background: "#f9fffb",
  cursor: "pointer",
  transition: "0.2s",
};

const cardTitle = {
  color: green,
  margin: "0 0 6px 0",
};

const cardText = {
  margin: 0,
  fontSize: 13,
  color: "#555",
};

const center = {
  textAlign: "center",
  padding: 40,
};
